using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a – type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person>  → found ({found!.Type.Name})");
}

// 2b – type that is NOT resolvable (empty resolver → nothing registered)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            // Strip every type so nothing resolves
            static ti => ti.Kind = JsonTypeInfoKind.None
        }
    }
};

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
{
    Console.WriteLine($"TryGetTypeInfo<Person>  → found (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person>  → not available (no exception thrown)");
}

public record Person(string Name, int Age);

